mapper.insert:
INSERT INTO TRANSACTIN_HIST (
    TX_ID, SELLER_NO, PRODUCT_NO, RECEIVER_NO, TX_TYPE, AMOUNT, TX_STATUS, CREATE_DT
) VALUES (
    TRANSACTIN_HIST_SEQ.NEXTVAL, 
    #{sellerNo}, #{productNo}, #{receiverNo}, #{txType}, #{amount}, #{txStatus}, SYSDATE
)

mapper.select:
SELECT T.*, P.PRODUCT_TITLE as PRODUCT_NAME, U.USER_NAME as PARTNER_NAME FROM TRANSACTIN_HIST T JOIN PRODUCT P ON T.PRODUCT_NO = P.PRODUCT_NO JOIN USER_INFO U ON (CASE WHEN T.SELLER_NO = #{userNum} THEN T.RECEIVER_NO ELSE T.SELLER_NO END) = U.USER_NUM WHERE 1=1
AND T.RECEIVER_NO = #{userNum}
AND T.SELLER_NO = #{userNum}
ORDER BY T.CREATE_DT DESC
